import React, { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { getSlots } from '../services/api';
import { useAuth } from '../contexts/AuthContext';
import './Slots.css';

export default function Slots() {
  const navigate = useNavigate();
  const { user } = useAuth();

  const { data: rawSlots = [], isLoading, isError, error } = useQuery({
    queryKey: ['slots'],
    queryFn: getSlots,
    staleTime: 5000,
  });

  // Normalize returned data: handle arrays of strings or objects
  const normalizedSlots = useMemo(() => {
    if (!Array.isArray(rawSlots)) return [];
    return rawSlots.map(s => {
      if (s == null) return null;
      if (typeof s === 'string' || typeof s === 'number') {
        return { slot_number: String(s), status: 'AVAILABLE' };
      }
      // ensure consistent keys: slot_number, slot_id, id
      return {
        slot_id: s.slot_id ?? s.id ?? null,
        id: s.id ?? s.slot_id ?? null,
        slot_number: s.slot_number ?? s.code ?? s.slotNumber ?? (s.slot_number === 0 ? '0' : s.slot_number ?? ''),
        status: String(s.status || s.state || 'AVAILABLE').toUpperCase(),
        level: s.level ?? null,
        type: s.type ?? s.slot_type ?? 'STANDARD',
        price_per_hour: s.price_per_hour ?? s.price ?? 5,
        occupied_by: s.occupied_by ?? s.occupant_id ?? null,
        occupied_since: s.occupied_since ?? s.occupiedAt ?? s.occupied_at ?? null,
        occupant_email: s.occupant_email ?? s.occupied_email ?? null,
        ...s, // keep any other fields
      };
    }).filter(Boolean);
  }, [rawSlots]);

  // Natural sort by slot_number (A-1, A-2, ..., A-10)
  const sortedSlots = useMemo(() => {
    return [...normalizedSlots].sort((a, b) =>
      (a.slot_number || '').localeCompare(b.slot_number || '', undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [normalizedSlots]);

  if (isLoading) return <div className="slots-loading">Loading slots…</div>;
  if (isError) return <div className="slots-error">Error loading slots: {String(error?.message || error)}</div>;

  const handleNavigateToBooking = (slot) => {
    if (!user) {
      navigate('/login');
      return;
    }
    const slotIdentifier = slot.id ?? slot.slot_id ?? slot.slot_number;
    navigate(`/booking/${slotIdentifier}`, { state: { selectedSlot: slot } });
  };

  return (
    <div className="slots-grid">
      {sortedSlots.map((s) => {
        const status = String(s.status || 'AVAILABLE').toUpperCase();
        const isAvailable = status === 'AVAILABLE';
        const key = s.slot_id ?? s.id ?? s.slot_number ?? `${s.slot_number}-${Math.random()}`;

        return (
          <div
            key={key}
            role="button"
            tabIndex={isAvailable ? 0 : -1}
            className={`slot-card slot-${status.toLowerCase()} ${isAvailable ? 'slot-available' : 'slot-unavailable'}`}
            onClick={() => isAvailable && handleNavigateToBooking(s)}
            onKeyDown={(e) => { if ((e.key === 'Enter' || e.key === ' ') && isAvailable) { e.preventDefault(); handleNavigateToBooking(s); } }}
            aria-disabled={!isAvailable}
            aria-label={`Slot ${s.slot_number ?? s.code ?? s.id} — ${status}`}
          >
            <div className="slot-card-row">
              <div className="slot-number">{s.slot_number ?? s.code ?? `#${s.id ?? s.slot_id}`}</div>
              <div className={`slot-badge ${isAvailable ? 'slot-badge-available' : 'slot-badge-taken'}`}>
                {isAvailable ? 'AVAILABLE' : status}
              </div>
            </div>

            <div className="slot-meta">
              {s.level ? `Level ${s.level}` : 'Level —'} · {s.type ?? 'Standard'} · ${s.price_per_hour ?? 5}/hr
            </div>

            <div className="slot-footer">
              <div className="slot-hint">
                {isAvailable ? 'Tap to reserve' : (s.occupied_by ? `Taken by ${String(s.occupied_by).slice(0,8)}` : status)}
              </div>

              <button
                type="button"
                className="slot-action"
                onClick={(e) => {
                  e.stopPropagation();
                  e.preventDefault();
                  if (!user) { navigate('/login'); return; }
                  if (!isAvailable) return;
                  const slotIdentifier = s.id ?? s.slot_id ?? s.slot_number;
                  navigate(`/booking/${slotIdentifier}`, { state: { selectedSlot: s } });
                }}
                disabled={!isAvailable || !user}
                aria-label={isAvailable ? `Reserve ${s.slot_number}` : `Cannot reserve ${s.slot_number}`}
              >
                {isAvailable ? 'Reserve' : 'Unavailable'}
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
}